create table if not exists public.financieras (
    id uuid primary key default gen_random_uuid(),
    slug text not null unique,
    nombre text not null,
    tipo text not null default 'banco',
    logo text not null,
    color text not null,
    tasa_min numeric not null,
    tasa_max numeric not null,
    cat_min numeric not null,
    cat_max numeric not null,
    enganche_pct integer not null,
    plazo_max integer not null,
    score_min integer,
    destacado boolean default false,
    aplica_para text,
    contacto text,
    notas text,
    orden integer default 0,
    activo boolean default true,
    created_at timestamp with time zone default timezone('utc'::text, now()) not null
);

alter table public.financieras enable row level security;

create policy "Lectura pública de financieras" on public.financieras for select using (true);

on conflict (slug) do nothing;
